using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
string apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

string model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

string? endpoint = Environment.GetEnvironmentVariable("OPENAI_ENDPOINT");

// ---------------------------------------------------------------------------
// Build the IChatClient
// ---------------------------------------------------------------------------
OpenAIClientOptions? clientOptions = null;
if (endpoint is not null)
{
    clientOptions = new OpenAIClientOptions { Endpoint = new Uri(endpoint) };
}

var openAIClient = clientOptions is null
    ? new OpenAIClient(apiKey)
    : new OpenAIClient(apiKey, clientOptions);

IChatClient chatClient = openAIClient.GetChatClient(model).AsIChatClient();

// ---------------------------------------------------------------------------
// Create tools
// ---------------------------------------------------------------------------
var noteTaker = new NoteTakingTool();
var webSearch = new WebSearchTool();

List<AITool> tools =
[
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(webSearch.FetchWebPage),
    AIFunctionFactory.Create(noteTaker.SaveNote),
    AIFunctionFactory.Create(noteTaker.GetAllNotes),
];

// ---------------------------------------------------------------------------
// Create the research agent
// ---------------------------------------------------------------------------
const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic the user
    provides and produce a well-organized summary of your findings.

    Follow this workflow:
    1. Search the web for the topic using the SearchWeb tool.
    2. Pick the most relevant results and fetch their content with FetchWebPage.
    3. As you discover important facts, save them as notes using SaveNote (use a
       short descriptive title for each note).
    4. When you have gathered enough information, call GetAllNotes to review
       everything you have collected.
    5. Finally, write a comprehensive summary that synthesizes your notes into a
       clear, well-structured report with sections and key takeaways.

    Be thorough but concise. Cite sources where possible.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    tools: tools);

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

ChatClientAgentSession session = new();

while (true)
{
    Console.Write("> ");
    string? input = Console.ReadLine();

    if (string.IsNullOrWhiteSpace(input))
        continue;

    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine("\nResearching... (this may take a moment)\n");

    try
    {
        AgentResponse response = await agent.RunAsync(input, session);
        Console.WriteLine(response.Text);
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }

    Console.WriteLine();
}

// ============================================================================
// Tool implementations
// ============================================================================

/// <summary>Provides web-search and page-fetching capabilities.</summary>
sealed class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html,application/xhtml+xml" },
        },
    };

    [Description("Search the web for a query and return a list of result snippets with URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        try
        {
            string encoded = WebUtility.UrlEncode(query);
            string url = $"https://html.duckduckgo.com/html/?q={encoded}";

            string html = await Http.GetStringAsync(url);

            // Extract result titles, snippets and URLs from DuckDuckGo HTML results
            var results = new StringBuilder();
            int count = 0;

            foreach (Match m in Regex.Matches(
                html,
                @"<a[^>]+class=""result__a""[^>]+href=""(?<url>[^""]+)""[^>]*>(?<title>.*?)</a>.*?<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
                RegexOptions.Singleline))
            {
                if (++count > 8) break;

                string title = StripHtml(m.Groups["title"].Value);
                string snippet = StripHtml(m.Groups["snippet"].Value);
                string resultUrl = WebUtility.UrlDecode(
                    Regex.Match(m.Groups["url"].Value, @"uddg=([^&]+)").Groups[1].Value);

                if (string.IsNullOrWhiteSpace(resultUrl))
                    resultUrl = m.Groups["url"].Value;

                results.AppendLine($"[{count}] {title}");
                results.AppendLine($"    URL: {resultUrl}");
                results.AppendLine($"    {snippet}");
                results.AppendLine();
            }

            return results.Length > 0
                ? results.ToString()
                : "No results found. Try rephrasing the query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL. Returns the first ~4000 characters of readable text.")]
    public async Task<string> FetchWebPage(
        [Description("The full URL of the page to fetch")] string url)
    {
        try
        {
            string html = await Http.GetStringAsync(url);

            // Strip scripts, styles, and HTML tags to get readable text
            html = Regex.Replace(html, @"<script[^>]*>.*?</script>", " ", RegexOptions.Singleline | RegexOptions.IgnoreCase);
            html = Regex.Replace(html, @"<style[^>]*>.*?</style>", " ", RegexOptions.Singleline | RegexOptions.IgnoreCase);
            html = Regex.Replace(html, @"<[^>]+>", " ");
            html = WebUtility.HtmlDecode(html);
            html = Regex.Replace(html, @"\s+", " ").Trim();

            return html.Length > 4000 ? html[..4000] + "\n...(truncated)" : html;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        string text = Regex.Replace(html, @"<[^>]+>", "");
        return WebUtility.HtmlDecode(text).Trim();
    }
}

/// <summary>In-memory note-taking tool for the agent to record findings.</summary>
sealed class NoteTakingTool
{
    private readonly Dictionary<string, string> _notes = new(StringComparer.OrdinalIgnoreCase);

    [Description("Save a research note with a short descriptive title. Overwrites any existing note with the same title.")]
    public string SaveNote(
        [Description("A short title for the note")] string title,
        [Description("The content / findings to record")] string content)
    {
        _notes[title] = content;
        return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        int i = 0;
        foreach (var (title, content) in _notes)
        {
            sb.AppendLine($"--- Note {++i}: {title} ---");
            sb.AppendLine(content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

