                string snippet = StripHtml(m.Groups["snippet"].Value);
                string resultUrl = WebUtility.UrlDecode(
                    Regex.Match(m.Groups["url"].Value, @"uddg=([^&]+)").Groups[1].Value);

                if (string.IsNullOrWhiteSpace(resultUrl))
                    resultUrl = m.Groups["url"].Value;

                results.AppendLine($"[{count}] {title}");
                results.AppendLine($"    URL: {resultUrl}");
                results.AppendLine($"    {snippet}");
                results.AppendLine();
            }

            return results.Length > 0
                ? results.ToString()
                : "No results found. Try rephrasing the query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL. Returns the first ~4000 characters of readable text.")]
    public async Task<string> FetchWebPage(
