    [Description("Save a research note with a short descriptive title. Overwrites any existing note with the same title.")]
    public string SaveNote(
        [Description("A short title for the note")] string title,
        [Description("The content / findings to record")] string content)
    {
        _notes[title] = content;
        return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        int i = 0;
        foreach (var (title, content) in _notes)
        {
            sb.AppendLine($"--- Note {++i}: {title} ---");
            sb.AppendLine(content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

